'use strict';

const elNome = document.querySelector('#nome');
const elIdade = document.querySelector('#idade');
const elTermos = document.querySelector('#termos');
const elPlano = document.querySelector('#plano');

const nome = String(elNome.value);
const idade = Number(elIdade.value);
const aceitou = Boolean(elTermos.checked);
const plano = String(elPlano.value);

console.log({ nome, idade, aceitou, plano });

function normText(x) {
  return String(x ?? '').trim().replace(/\s+/g, ' ');
}

function toNumberOrNull(raw) {
  const s = String(raw ?? '').trim().replace(',', '.');
  if (s.length === 0) return null;
  const n = Number(s);
  return Number.isNaN(n) ? null : n;
}

function validarNome(raw) {
  const nome = normText(raw);
  if (nome.length < 3) return { ok: false, msg: 'nome deve ter 3+ caracteres' };
  return { ok: true, value: nome };
}

function validarIdade(raw) {
  const n = toNumberOrNull(raw);
  if (n === null) return { ok: false, msg: 'idade inválida' };
  if (!Number.isInteger(n)) return { ok: false, msg: 'idade deve ser inteira' };
  if (n < 0 || n > 130) return { ok: false, msg: 'idade fora do intervalo' };
  return { ok: true, value: n };
}

function validarEmailSimples(raw) {
  const email = normText(raw).toLowerCase();
  if (!email) return { ok: false, msg: 'email obrigatório' };
  if (email.includes(' ')) return { ok: false, msg: 'email não pode ter espaço' };
  const parts = email.split('@');
  if (parts.length !== 2) return { ok: false, msg: 'email deve ter um @' };
  const [u, d] = parts;
  if (!u || !d || !d.includes('.')) return { ok: false, msg: 'email inválido' };
  return { ok: true, value: email };
}

function validarForm({ nome, idade, email, aceitou, plano }) {
  const erros = {};

  const n = validarNome(nome);
  if (!n.ok) erros.nome = n.msg;

  const i = validarIdade(idade);
  if (!i.ok) erros.idade = i.msg;

  const e = validarEmailSimples(email);
  if (!e.ok) erros.email = e.msg;

  if (!aceitou) erros.termos = 'você deve aceitar os termos';

  const planosOk = ['FREE', 'PRO', 'TEAM'];
  if (!planosOk.includes(String(plano))) erros.plano = 'plano inválido';

  const ok = Object.keys(erros).length === 0;
  if (!ok) return { ok: false, erros };

  const payload = { nome: n.value, idade: i.value, email: e.value, aceitou: true, plano };
  return { ok: true, payload };
}

function limparErros() {
  for (const el of document.querySelectorAll('[data-err]')) {
    el.textContent = '';
  }
}

function renderErros(erros) {
  limparErros();
  for (const [campo, msg] of Object.entries(erros)) {
    const el = document.querySelector(`[data-err="${campo}"]`);
    if (el) el.textContent = msg;
  }
}

const form = document.querySelector('#form');
form.addEventListener('submit', (ev) => {
  ev.preventDefault();

  const data = {
    nome: document.querySelector('#nome').value,
    idade: document.querySelector('#idade').value,
    email: document.querySelector('#email').value,
    aceitou: document.querySelector('#termos').checked,
    plano: document.querySelector('#plano').value,
  };

  const res = validarForm(data);
  if (!res.ok) return renderErros(res.erros);

  console.log('payload pronto para enviar:', res.payload);
});
